class Solution {
public:
    int vowelStrings(vector<string>& words, int left, int right) {
        int count = 0;
        for (int i = left; i <= right; i++) {
            string word = words[i];
            if (isVowel(word[0]) && isVowel(word[word.size() - 1])) {
                count++;
            }
        }
        return count;
    }

    bool isVowel(char c) {
        string vowels = "aeiou";
        return vowels.find(c) != string::npos;
    }
};
